sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;
    if (oldValue === newValue) return;

    // Table Aggregate fields
    g_form.setValue('src_table', '');
    g_form.setValue('src_filter', '');
    g_form.setValue('src_aggregate', '');
    g_form.setValue('src_aggregate_field', '');
    g_form.setValue('src_group_by', '');
    g_form.setValue('src_group_by_2', '');
    g_form.setValue('src_order_by', '');
    g_form.setValue('src_limit', '');
    g_form.setValue('src_x_field', '');
    g_form.setValue('src_y_field', '');
    g_form.setValue('src_source_field', '');
    g_form.setValue('src_target_field', '');

    // PA Indicator fields
    g_form.setValue('src_indicator', '');
    g_form.setValue('src_breakdown', '');
    g_form.setValue('src_elements', '');
    g_form.setValue('src_lookback_days', '');

    // Staged External fields
    g_form.setValue('src_staged_table', '');
    g_form.setValue('src_staged_filter', '');
    g_form.setValue('src_label_field', '');
    g_form.setValue('src_value_field', '');

    // Scripted fields
    g_form.setValue('src_script_include', '');
    g_form.setValue('src_method', '');
    g_form.setValue('src_params', '');
}
